mapper.update:
        /** UsptMvnCompanyDao.update */
		update uspt_mvn_company set
		      mvn_cmpny_st              = #{mvnCmpnySt}
		    , mvn_cmpny_st_dt           = #{mvnCmpnyStDt}
		    , updater_id                = #{updaterId}
		    , updated_dt                = #{updatedDt}
		where
		    mvn_id = #{mvnId}
